334‚Üí    private suspend fun getSchedulingStatesWithContext(): ByteArray {
335‚Üí        val state = queueState.await() ?: return ByteArray(0)
336‚Üí        return state.schedulingStatesWithContext().toBuilder()
337‚Üí            .mergeStates(
338‚Üí                state.states.toBuilder().mergeCurrent(
339‚Üí                    state.states.current.toBuilder()
340‚Üí                        .setCustomData(state.topCard.toBackendCard().customData).build()
341‚Üí                ).build()
342‚Üí            )
343‚Üí            .build()
344‚Üí            .toByteArray()
345‚Üí    }
