347‚Üí    private suspend fun setSchedulingStates(bytes: ByteArray): ByteArray {
348‚Üí        val state = queueState.await() ?: return ByteArray(0)
349‚Üí        val req = SetSchedulingStatesRequest.parseFrom(bytes)
